void solve(int CASE)
{
	ll n, m, k; cin >> n >> m >> k;
	var mp = vector<ll>(m + 1);
	fa(i, 1, m) {
		ll x; cin >> x;
		mp[x]++;
	}
	var p = vector<pll>(n + 1);
	fa(i, 1, n) {
		ll x, y, z; cin >> x >> y >> z;
		k -= y;
		p[i] = { x,z - y };
	}
	sort(all1(p));

	int j = p[1].px;
	while (j <= m and !mp[j])j++;
	var Q = priority_queue<ll>();
	int ans = 0;
	fa(i, 1, n) {
		while (j <= m and !mp[j])j++;
		Q.push(p[i].py);
		while ((i == n or p[i + 1].px > j) and j <= m) {
			while (Q.size() and mp[j]) {
				Q.pop();
				mp[j]--;
				ans++;
			}
			j++;
		}
	}

	var st = stack<ll>();
	while (Q.size()) {
		st.push(Q.top());
		Q.pop();
	}
	while (st.size() and k >= st.top()) {
		k -= st.top();
		st.pop();
		ans++;
	}

	cout << ans << endl;
	return;
}
